export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioResult {
  results: StepResult[];
}

interface MainItemSpec {
  insuranceValue: number;
  basePremium: number;
}

const MAIN_ITEMS: Record<string, MainItemSpec> = {
  sword: { insuranceValue: 1000, basePremium: 100 },
  amulet: { insuranceValue: 600, basePremium: 60 },
  staff: { insuranceValue: 800, basePremium: 80 },
  potion: { insuranceValue: 400, basePremium: 40 },
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const COMPONENT_INSURANCE = 250;
const COMPONENT_PREMIUM = 25;
const BLOCK_PREMIUM = 60;
const DEDUCTIBLE = 100;
const PROCESSING_FEE = 5;

function isMainItem(type: string): boolean {
  return type in MAIN_ITEMS;
}

function isComponent(type: string): boolean {
  return COMPONENT_TYPES.has(type);
}

function validateItemTypes(items: Item[]): void {
  for (const item of items) {
    if (!isMainItem(item.type) && !isComponent(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }
}

interface PolicyItem {
  item: Item;
  insuranceValue: number;
  basePremium: number;
}

interface Policy {
  items: PolicyItem[];
  insuranceSum: number;
  cap: number;
  remainingCap: number;
}

function itemInsuranceValue(item: Item): number {
  if (isMainItem(item.type)) {
    return MAIN_ITEMS[item.type].insuranceValue;
  }
  return COMPONENT_INSURANCE;
}

function itemBasePremium(item: Item): number {
  if (isMainItem(item.type)) {
    return MAIN_ITEMS[item.type].basePremium;
  }
  return COMPONENT_PREMIUM;
}

function itemSurchargeMultiplier(item: Item): number {
  let mult = 1;
  if (item.cursed) mult += 0.5;
  if ((item.enchantment ?? 0) >= 5) mult += 0.3;
  return mult;
}

function computeComponentsBasePremium(components: Item[]): number {
  const byType = new Map<string, number>();
  for (const c of components) {
    byType.set(c.type, (byType.get(c.type) ?? 0) + 1);
  }
  let total = 0;
  for (const count of byType.values()) {
    const blocks = Math.floor(count / 3);
    const remainder = count - blocks * 3;
    total += blocks * BLOCK_PREMIUM + remainder * COMPONENT_PREMIUM;
  }
  return total;
}

function computePolicyItems(items: Item[]): PolicyItem[] {
  return items.map((item) => ({
    item,
    insuranceValue: itemInsuranceValue(item),
    basePremium: itemBasePremium(item),
  }));
}

function computePolicy(items: Item[]): Policy {
  const policyItems = computePolicyItems(items);
  const insuranceSum = policyItems.reduce((sum, pi) => sum + pi.insuranceValue, 0);
  const cap = insuranceSum * 2;
  return {
    items: policyItems,
    insuranceSum,
    cap,
    remainingCap: cap,
  };
}

interface PremiumContext {
  yearsWithMHPCO: number;
  isFirstContract: boolean;
}

function computePremium(items: Item[], ctx: PremiumContext): number {
  validateItemTypes(items);

  if (items.length === 0) {
    return PROCESSING_FEE;
  }

  const mainItems = items.filter((i) => isMainItem(i.type));
  const components = items.filter((i) => isComponent(i.type));

  let policyBase = 0;

  // Main items: base × per-item surcharges
  for (const item of mainItems) {
    const base = itemBasePremium(item);
    const surcharged = base * itemSurchargeMultiplier(item);
    policyBase += surcharged;
  }

  // Components: block discount applied, then per-item surcharges proportionally?
  // Per the spec, components don't typically have enchantment/curse, but if they did,
  // surcharges apply to the item's base premium. With block, a component's effective
  // base premium is shared. We'll keep it simple: apply surcharges only to components,
  // but block pricing applies to total premium of like components.
  // Actually, simpler: compute block-discounted base for components, ignore curse/enchant
  // on components (spec doesn't show any examples of cursed runes).
  policyBase += computeComponentsBasePremium(components);

  // Policy-wide modifiers
  let multiplier = 1;
  if (ctx.yearsWithMHPCO >= 2) multiplier -= 0.2;
  if (ctx.isFirstContract) multiplier += 0.1;
  else multiplier -= 0.15;

  // First insurance surcharge applies per item (each item in a quote is a first insurance)
  // From spec: "10% initial assessment surcharge" on first insurance.
  // Integration example: 100 base + 50 curse + 10 first insurance = 160 + 5 = 165.
  // The 10 G is 10% of 100 G base. So this is 10% of policy base premium (sum of bases).
  // Per spec: "policy-wide modifiers (loyalty, first insurance, follow-up contract) apply to the policy base premium"
  let policyMultiplier = 0;
  if (ctx.yearsWithMHPCO >= 2) policyMultiplier -= 0.2;
  if (ctx.isFirstContract) policyMultiplier += 0.1;
  else policyMultiplier -= 0.15;

  // Wait — second integration example: customer 3 years, follow-up, cursed enchantment-7 sword:
  // 100 base + 50 curse + 30 enchant - 20 loyalty + 10 first insurance - 15 follow-up = 155
  // So first insurance applies even on follow-up contracts. Per the note:
  // "each item in a quote is treated as a first insurance, regardless of customer history"
  // So the +10% is policy-wide (sum of bases × 0.1) AND it's always applied.
  // Actually re-reading: "A first insurance carries a 10% initial assessment surcharge."
  // The note says each item gets it. So it's ALWAYS +10% on the policy base.
  policyMultiplier = 0;
  if (ctx.yearsWithMHPCO >= 2) policyMultiplier -= 0.2;
  policyMultiplier += 0.1; // first insurance always applies per the clarification
  if (!ctx.isFirstContract) policyMultiplier -= 0.15;

  // Compute policy base premium (sum of item bases, no per-item surcharges)
  // For modifier purposes per spec: "policy-wide modifiers ... apply to the policy base premium (the sum of all item base premiums)"
  let plainPolicyBase = 0;
  for (const item of mainItems) plainPolicyBase += itemBasePremium(item);
  plainPolicyBase += computeComponentsBasePremium(components);

  const policyWideAdjustment = plainPolicyBase * policyMultiplier;

  const beforeFee = policyBase + policyWideAdjustment;
  const total = beforeFee + PROCESSING_FEE;

  return Math.ceil(total);
}

function findMatchingItem(policy: Policy, itemType: string, used: Set<number>): PolicyItem | null {
  for (let i = 0; i < policy.items.length; i++) {
    if (used.has(i)) continue;
    if (policy.items[i].item.type === itemType) {
      used.add(i);
      return policy.items[i];
    }
  }
  return null;
}

function computeItemPayout(policyItem: PolicyItem, damageAmount: number): number {
  const item = policyItem.item;
  const isDragon = item.material === "dragon";
  const isHighEnchant = (item.enchantment ?? 0) >= 8;

  let reimbursement: number;
  if (isHighEnchant) {
    reimbursement = damageAmount * 0.5;
  } else if (isDragon) {
    reimbursement = damageAmount;
  } else {
    reimbursement = damageAmount;
  }

  const afterDeductible = reimbursement - DEDUCTIBLE;
  return Math.max(0, afterDeductible);
}

function processClaim(policy: Policy, incident: Incident): ClaimResult {
  if (incident.damages.some((d) => d.amount < 0)) {
    throw new Error("Damage amount cannot be negative");
  }

  const used = new Set<number>();
  let totalPayout = 0;

  for (const damage of incident.damages) {
    const matched = findMatchingItem(policy, damage.itemType, used);
    if (!matched) {
      throw new Error(`Damage references item not in policy: ${damage.itemType}`);
    }
    totalPayout += computeItemPayout(matched, damage.amount);
  }

  // Round down (in MHPCO's favor)
  let payout = Math.floor(totalPayout);

  // Apply remaining cap
  if (payout > policy.remainingCap) {
    payout = policy.remainingCap;
  }

  policy.remainingCap -= payout;

  return {
    payout,
    remainingCap: policy.remainingCap,
  };
}

export function runScenario(scenario: Scenario): ScenarioResult {
  const results: StepResult[] = [];
  const policies = new Map<number, Policy>();
  let quoteCount = 0;

  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];

    if (step.op === "quote") {
      validateItemTypes(step.items);
      const isFirstContract = quoteCount === 0;
      const premium = computePremium(step.items, {
        yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
        isFirstContract,
      });
      const policy = computePolicy(step.items);
      policies.set(i, policy);
      results.push({ premium });
      quoteCount++;
    } else {
      const policy = policies.get(step.policy);
      if (!policy) {
        throw new Error(`Claim references unknown policy: ${step.policy}`);
      }
      const result = processClaim(policy, step.incident);
      results.push(result);
    }
  }

  return { results };
}

