60	const MAIN_ITEMS: Record<string, MainItemSpec> = {
61	  sword: { insuranceValue: 1000, basePremium: 100 },
62	  amulet: { insuranceValue: 600, basePremium: 60 },
63	  staff: { insuranceValue: 800, basePremium: 80 },
64	  potion: { insuranceValue: 400, basePremium: 40 },
65	};
66	
67	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
68	
69	const COMPONENT_INSURANCE = 250;
70	const COMPONENT_PREMIUM = 25;
71	const BLOCK_PREMIUM = 60;
72	const DEDUCTIBLE = 100;
73	const PROCESSING_FEE = 5;
74	
75	function isMainItem(type: string): boolean {
76	  return type in MAIN_ITEMS;
77	}
78	
79	function isComponent(type: string): boolean {
80	  return COMPONENT_TYPES.has(type);
81	}
82	
83	function validateItemTypes(items: Item[]): void {
84	  for (const item of items) {
85	    if (!isMainItem(item.type) && !isComponent(item.type)) {
86	      throw new Error(`Unknown item type: ${item.type}`);
87	    }
88	  }
89	}
90	
91	interface Policy {
92	  items: Item[];
93	  remainingCap: number;
94	}
95	
96	function itemInsuranceValue(item: Item): number {
97	  return isMainItem(item.type) ? MAIN_ITEMS[item.type].insuranceValue : COMPONENT_INSURANCE;
98	}
99	
100	function itemBasePremium(item: Item): number {
101	  return isMainItem(item.type) ? MAIN_ITEMS[item.type].basePremium : COMPONENT_PREMIUM;
102	}
103	
104	function itemSurchargeMultiplier(item: Item): number {
105	  let mult = 1;
106	  if (item.cursed) mult += 0.5;
107	  if ((item.enchantment ?? 0) >= 5) mult += 0.3;
108	  return mult;
109	}
110	
111	function priceForLikeComponents(count: number): number {
112	  // Exactly 3 alike components form a discounted block; otherwise price per item.
113	  return count === 3 ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
114	}
115	
116	function computeComponentsBasePremium(components: Item[]): number {
117	  const countsByType = new Map<string, number>();
118	  for (const component of components) {
119	    countsByType.set(component.type, (countsByType.get(component.type) ?? 0) + 1);
120	  }
121	  let total = 0;
122	  for (const count of countsByType.values()) {
123	    total += priceForLikeComponents(count);
124	  }
125	  return total;
126	}
127	
128	function computePolicy(items: Item[]): Policy {
129	  const insuranceSum = items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
130	  return {
131	    items: [...items],
132	    remainingCap: insuranceSum * 2,
133	  };
134	}
135	
136	interface PremiumContext {
137	  yearsWithMHPCO: number;
138	  isFirstContract: boolean;
139	}
140	
141	function sumMainItemsBase(mainItems: Item[]): number {
142	  return mainItems.reduce((sum, item) => sum + itemBasePremium(item), 0);
143	}
144	
145	function sumMainItemsSurcharged(mainItems: Item[]): number {
146	  return mainItems.reduce(
147	    (sum, item) => sum + itemBasePremium(item) * itemSurchargeMultiplier(item),
148	    0,
149	  );
150	}
151	
152	function policyWideMultiplier(ctx: PremiumContext): number {
153	  // Each item is treated as a first insurance (10% always applies).
154	  // Loyalty discount (-20%) at 2+ years; renewal discount (-15%) when not first contract.
155	  let multiplier = 0.1;
156	  if (ctx.yearsWithMHPCO >= 2) multiplier -= 0.2;
157	  if (!ctx.isFirstContract) multiplier -= 0.15;
158	  return multiplier;
159	}
160	
161	function computePremium(items: Item[], ctx: PremiumContext): number {
162	  if (items.length === 0) {
163	    return PROCESSING_FEE;
164	  }
165	
166	  const mainItems = items.filter((i) => isMainItem(i.type));
167	  const components = items.filter((i) => isComponent(i.type));
168	
169	  const componentsBase = computeComponentsBasePremium(components);
170	  const surchargedBase = sumMainItemsSurcharged(mainItems) + componentsBase;
171	  const plainBase = sumMainItemsBase(mainItems) + componentsBase;
172	
173	  const total = surchargedBase + plainBase * policyWideMultiplier(ctx) + PROCESSING_FEE;
174	  return Math.ceil(total);
175	}
176	
177	function reimbursementFor(item: Item, damageAmount: number): number {
178	  const isHighEnchant = (item.enchantment ?? 0) >= 8;
179	  return isHighEnchant ? damageAmount * 0.5 : damageAmount;
180	}
181	
182	function payoutFor(item: Item, damageAmount: number): number {
183	  return Math.max(0, reimbursementFor(item, damageAmount) - DEDUCTIBLE);
184	}
185	
186	function takeMatchingItem(available: Item[], itemType: string): Item {
187	  const index = available.findIndex((item) => item.type === itemType);
188	  if (index === -1) {
189	    throw new Error(`Damage references item not in policy: ${itemType}`);
190	  }
191	  return available.splice(index, 1)[0];
192	}
193	
194	function processClaim(policy: Policy, incident: Incident): ClaimResult {
195	  if (incident.damages.some((d) => d.amount < 0)) {
196	    throw new Error("Damage amount cannot be negative");
197	  }
198	
199	  const available = [...policy.items];
200	  const grossPayout = incident.damages.reduce((sum, damage) => {
201	    const matched = takeMatchingItem(available, damage.itemType);
202	    return sum + payoutFor(matched, damage.amount);
203	  }, 0);
204	
205	  // Round down (in MHPCO's favor), then cap at remaining coverage.
206	  const payout = Math.min(Math.floor(grossPayout), policy.remainingCap);
207	  policy.remainingCap -= payout;
208	
209	  return { payout, remainingCap: policy.remainingCap };
210	}
211	
212	function handleQuote(
213	  step: QuoteStep,
214	  stepIndex: number,
215	  customer: Customer,
216	  policies: Map<number, Policy>,
217	): QuoteResult {
218	  validateItemTypes(step.items);
219	  const isFirstContract = policies.size === 0;
220	  const premium = computePremium(step.items, {
221	    yearsWithMHPCO: customer.yearsWithMHPCO,
222	    isFirstContract,
223	  });
224	  policies.set(stepIndex, computePolicy(step.items));
225	  return { premium };
226	}
227	
228	function handleClaim(step: ClaimStep, policies: Map<number, Policy>): ClaimResult {
229	  const policy = policies.get(step.policy);
230	  if (!policy) {
231	    throw new Error(`Claim references unknown policy: ${step.policy}`);
232	  }
233	  return processClaim(policy, step.incident);
234	}
235	
236	export function runScenario(scenario: Scenario): ScenarioResult {
237	  const policies = new Map<number, Policy>();
238	  const results = scenario.steps.map((step, i) =>
239	    step.op === "quote"
240	      ? handleQuote(step, i, scenario.customer, policies)
241	      : handleClaim(step, policies),
242	  );
243	  return { results };
244	}
